// Input: Encoding of k-tape TM, input string w
// Tape encoding: #content₁#content₂#...#content_k#
// Position marker: X placed under head position on each virtual tape

BEGIN
  // Initialize: encode input on tape 1, others empty with markers at leftmost
  WRITE # + w + # + # + ... + # + X  // X marks head position on tape 1

  WHILE not HALT DO
    // Phase 1: Right-to-left scan to collect all symbols under heads
    current_state ← current_state_of_M
    MOVE_RIGHT until rightmost #
    // Record symbols under each head position

    // Phase 2: Find applicable transition in M's δ table
    FOR each tape i from 1 to k DO
      symbol_i ← symbol_under_marker_i
    END FOR

    // Look up δ(current_state, symbol_1, ..., symbol_k)
    new_state, new_symbols[], directions[] ← δ(current_state, symbol_1, ..., symbol_k)

    // Phase 3: Left-to-right scan to update tape and move markers
    FOR each tape i from 1 to k DO
      WRITE new_symbol_i
      IF directions[i] = 'R' THEN move marker right
      IF directions[i] = 'L' THEN move marker left
    END FOR

    current_state ← new_state

    IF current_state = q_accept THEN ACCEPT
    IF current_state = q_reject THEN REJECT
  END WHILE
END
